     1→/**
     2→ * markdown-parser.js
     3→ * 외부 라이브러리 없이 구현한 마크다운 파서
     4→ *
     5→ * 지원 기능:
     6→ * - 제목 (h1~h6)
     7→ * - 굵게, 기울임, 굵은 기울임
     8→ * - 인라인 코드
     9→ * - 코드 블록 (언어 레이블 포함)
    10→ * - 링크, 이미지
    11→ * - 순서 없는/있는 목록 (중첩 포함)
    12→ * - 인용구 (중첩 포함)
    13→ * - 수평선
    14→ * - 문단, 줄바꿈
    15→ * - 이스케이프 문자
    16→ */
    17→
    18→const MarkdownParser = (() => {
    19→  // HTML 특수문자 이스케이프 (XSS 방지)
    20→  function escapeHtml(text) {
    21→    return text
    22→      .replace(/&/g, '&amp;')
    23→      .replace(/</g, '&lt;')
    24→      .replace(/>/g, '&gt;')
    25→      .replace(/"/g, '&quot;')
    26→      .replace(/'/g, '&#39;');
    27→  }
    28→
    29→  // 이스케이프된 마크다운 문자를 플레이스홀더로 변환
    30→  function protectEscapes(text) {
    31→    return text.replace(/\\([\\`*_{}[\]()#+\-.!~|])/g, (match, char) => {
    32→      return `\x00ESC${char.charCodeAt(0)}\x00`;
    33→    });
    34→  }
    35→
    36→  // 플레이스홀더를 실제 문자로 복원
    37→  function restoreEscapes(text) {
    38→    return text.replace(/\x00ESC(\d+)\x00/g, (match, code) => {
    39→      return escapeHtml(String.fromCharCode(Number(code)));
    40→    });
    41→  }
    42→
    43→  // 인라인 요소 파싱 (굵게, 기울임, 코드, 링크, 이미지 등)
    44→  function parseInline(text) {
    45→    text = protectEscapes(text);
    46→
    47→    // 인라인 코드 (백틱)
    48→    text = text.replace(/`([^`\n]+?)`/g, (match, code) => {
    49→      return `<code>${escapeHtml(code)}</code>`;
    50→    });
    51→
    52→    // 이미지: ![alt](url "title")
    53→    text = text.replace(/!\[([^\]]*)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (match, alt, src, title) => {
    54→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    55→      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    56→    });
    57→
    58→    // 링크: [text](url "title")
    59→    text = text.replace(/\[([^\]]+)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (match, linkText, href, title) => {
    60→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    61→      return `<a href="${escapeHtml(href)}"${titleAttr}>${linkText}</a>`;
    62→    });
    63→
    64→    // 굵은 기울임: ***text*** 또는 ___text___
    65→    text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    66→    text = text.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');
    67→
    68→    // 굵게: **text** 또는 __text__
    69→    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    70→    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    71→
    72→    // 기울임: *text* 또는 _text_
    73→    text = text.replace(/\*([^*\n]+?)\*/g, '<em>$1</em>');
    74→    text = text.replace(/_([^_\n]+?)_/g, '<em>$1</em>');
    75→
    76→    // ~~취소선~~
    77→    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    78→
    79→    // 줄바꿈: 두 개 이상의 공백 + 줄바꿈 또는 백슬래시 + 줄바꿈
    80→    text = text.replace(/  +\n/g, '<br>\n');
    81→    text = text.replace(/\\\n/g, '<br>\n');
    82→
    83→    text = restoreEscapes(text);
    84→    return text;
    85→  }
    86→
    87→  // 목록 파싱 (중첩 지원)
    88→  function parseList(lines, startIndex, baseIndent) {
    89→    let html = '';
    90→    let i = startIndex;
    91→    let listType = null;
    92→
    93→    while (i < lines.length) {
    94→      const line = lines[i];
    95→
    96→      // 빈 줄: 목록 종료 가능성 체크
    97→      if (line.trim() === '') {
    98→        // 다음 줄이 같은 들여쓰기의 목록 항목이면 계속
    99→        if (i + 1 < lines.length) {
   100→          const nextLine = lines[i + 1];
   101→          const nextIndent = nextLine.match(/^(\s*)/)[1].length;
   102→          const isNextListItem = /^(\s*)([-*+]|\d+[.)]) /.test(nextLine);
   103→          if (isNextListItem && nextIndent >= baseIndent) {
   104→            i++;
   105→            continue;
   106→          }
   107→        }
   108→        break;
   109→      }
   110→
   111→      // 현재 줄의 들여쓰기 계산
   112→      const currentIndent = line.match(/^(\s*)/)[1].length;
   113→
   114→      // 기본 들여쓰기보다 적으면 종료
   115→      if (currentIndent < baseIndent) {
   116→        break;
   117→      }
   118→
   119→      // 중첩 목록 처리
   120→      if (currentIndent > baseIndent) {
   121→        const nestedResult = parseList(lines, i, currentIndent);
   122→        html += nestedResult.html;
   123→        i = nestedResult.nextIndex;
   124→        continue;
   125→      }
   126→
   127→      // 순서 없는 목록 항목
   128→      const ulMatch = line.match(/^(\s*)([-*+]) (.*)$/);
   129→      if (ulMatch) {
   130→        if (listType !== 'ul') {
   131→          if (listType !== null) {
   132→            html += listType === 'ol' ? '</ol>' : '</ul>';
   133→          }
   134→          listType = 'ul';
   135→          html += '<ul>';
   136→        }
   137→        html += `<li>${parseInline(ulMatch[3])}`;
   138→
   139→        // 다음 줄이 더 깊은 들여쓰기인지 확인
   140→        if (i + 1 < lines.length) {
   141→          const nextLine = lines[i + 1];
   142→          const nextIndent = nextLine.match(/^(\s*)/)[1].length;
   143→          if (nextIndent > currentIndent && /^(\s*)([-*+]|\d+[.)]) /.test(nextLine)) {
   144→            const nestedResult = parseList(lines, i + 1, nextIndent);
   145→            html += nestedResult.html;
   146→            i = nestedResult.nextIndex;
   147→          } else {
   148→            i++;
   149→          }
   150→        } else {
   151→          i++;
   152→        }
   153→        html += '</li>';
   154→        continue;
   155→      }
   156→
   157→      // 순서 있는 목록 항목
   158→      const olMatch = line.match(/^(\s*)(\d+)[.)]\s(.*)$/);
   159→      if (olMatch) {
   160→        if (listType !== 'ol') {
   161→          if (listType !== null) {
   162→            html += listType === 'ul' ? '</ul>' : '</ol>';
   163→          }
   164→          listType = 'ol';
   165→          html += '<ol>';
   166→        }
   167→        html += `<li>${parseInline(olMatch[3])}`;
   168→
   169→        // 다음 줄이 더 깊은 들여쓰기인지 확인
   170→        if (i + 1 < lines.length) {
   171→          const nextLine = lines[i + 1];
   172→          const nextIndent = nextLine.match(/^(\s*)/)[1].length;
   173→          if (nextIndent > currentIndent && /^(\s*)([-*+]|\d+[.)]) /.test(nextLine)) {
   174→            const nestedResult = parseList(lines, i + 1, nextIndent);
   175→            html += nestedResult.html;
   176→            i = nestedResult.nextIndex;
   177→          } else {
   178→            i++;
   179→          }
   180→        } else {
   181→          i++;
   182→        }
   183→        html += '</li>';
   184→        continue;
   185→      }
   186→
   187→      // 목록 항목이 아닌 줄
   188→      break;
   189→    }
   190→
   191→    if (listType === 'ul') html += '</ul>';
   192→    if (listType === 'ol') html += '</ol>';
   193→
   194→    return { html, nextIndex: i };
   195→  }
   196→
   197→  // 인용구 파싱 (중첩 지원)
   198→  function parseBlockquote(lines, startIndex) {
   199→    let innerLines = [];
   200→    let i = startIndex;
   201→
   202→    while (i < lines.length) {
   203→      const line = lines[i];
   204→      if (/^> ?/.test(line)) {
   205→        innerLines.push(line.replace(/^> ?/, ''));
   206→        i++;
   207→      } else if (line.trim() === '' && i + 1 < lines.length && /^> ?/.test(lines[i + 1])) {
   208→        innerLines.push('');
   209→        i++;
   210→      } else {
   211→        break;
   212→      }
   213→    }
   214→
   215→    const innerHtml = parse(innerLines.join('\n'));
   216→    return { html: `<blockquote>${innerHtml}</blockquote>`, nextIndex: i };
   217→  }
   218→
   219→  // 코드 블록 파싱
   220→  function parseCodeBlock(lines, startIndex, lang) {
   221→    let codeLines = [];
   222→    let i = startIndex + 1;
   223→
   224→    while (i < lines.length && !lines[i].startsWith('```')) {
   225→      codeLines.push(lines[i]);
   226→      i++;
   227→    }
   228→
   229→    const code = escapeHtml(codeLines.join('\n'));
   230→    const langLabel = lang
   231→      ? `<span class="code-lang-label">${escapeHtml(lang)}</span>`
   232→      : '';
   233→    const html = `<div class="code-block-wrapper">${langLabel}<pre><code>${code}</code></pre></div>`;
   234→
   235→    return { html, nextIndex: i + 1 };
   236→  }
   237→
   238→  // 들여쓰기 코드 블록 파싱 (공백 4개 또는 탭)
   239→  function parseIndentedCodeBlock(lines, startIndex) {
   240→    let codeLines = [];
   241→    let i = startIndex;
   242→
   243→    while (i < lines.length && /^(    |\t)/.test(lines[i])) {
   244→      codeLines.push(lines[i].replace(/^(    |\t)/, ''));
   245→      i++;
   246→    }
   247→
   248→    const code = escapeHtml(codeLines.join('\n'));
   249→    return { html: `<pre><code>${code}</code></pre>`, nextIndex: i };
   250→  }
   251→
   252→  // 메인 파서
   253→  function parse(markdown) {
   254→    if (!markdown || markdown.trim() === '') {
   255→      return '';
   256→    }
   257→
   258→    const lines = markdown.split('\n');
   259→    let html = '';
   260→    let i = 0;
   261→    let paragraphLines = [];
   262→
   263→    // 누적된 문단 줄을 HTML로 변환
   264→    function flushParagraph() {
   265→      if (paragraphLines.length === 0) return;
   266→      const content = paragraphLines.join('\n').trim();
   267→      if (content) {
   268→        html += `<p>${parseInline(content)}</p>\n`;
   269→      }
   270→      paragraphLines = [];
   271→    }
   272→
   273→    while (i < lines.length) {
   274→      const line = lines[i];
   275→      const trimmed = line.trim();
   276→
   277→      // 빈 줄: 문단 구분
   278→      if (trimmed === '') {
   279→        flushParagraph();
   280→        i++;
   281→        continue;
   282→      }
   283→
   284→      // 코드 블록 (``` 또는 ~~~)
   285→      const fencedCodeMatch = line.match(/^(`{3,}|~{3,})(\w+)?/);
   286→      if (fencedCodeMatch) {
   287→        flushParagraph();
   288→        const lang = fencedCodeMatch[2] || '';
   289→        const result = parseCodeBlock(lines, i, lang);
   290→        html += result.html + '\n';
   291→        i = result.nextIndex;
   292→        continue;
   293→      }
   294→
   295→      // 들여쓰기 코드 블록
   296→      if (/^(    |\t)/.test(line)) {
   297→        flushParagraph();
   298→        const result = parseIndentedCodeBlock(lines, i);
   299→        html += result.html + '\n';
   300→        i = result.nextIndex;
   301→        continue;
   302→      }
   303→
   304→      // 제목 (ATX 스타일: # ~ ######)
   305→      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/);
   306→      if (headingMatch) {
   307→        flushParagraph();
   308→        const level = headingMatch[1].length;
   309→        const content = parseInline(headingMatch[2].trim());
   310→        html += `<h${level}>${content}</h${level}>\n`;
   311→        i++;
   312→        continue;
   313→      }
   314→
   315→      // 수평선 (---, ***, ___)
   316→      if (/^(?:[-*_]){3,}\s*$/.test(trimmed)) {
   317→        flushParagraph();
   318→        html += '<hr>\n';
   319→        i++;
   320→        continue;
   321→      }
   322→
   323→      // Setext 스타일 제목 (=== 또는 ---)
   324→      if (i + 1 < lines.length) {
   325→        const nextLine = lines[i + 1];
   326→        if (/^=+\s*$/.test(nextLine) && trimmed) {
   327→          flushParagraph();
   328→          html += `<h1>${parseInline(trimmed)}</h1>\n`;
   329→          i += 2;
   330→          continue;
   331→        }
   332→        if (/^-+\s*$/.test(nextLine) && trimmed && nextLine.length >= 2) {
   333→          flushParagraph();
   334→          html += `<h2>${parseInline(trimmed)}</h2>\n`;
   335→          i += 2;
   336→          continue;
   337→        }
   338→      }
   339→
   340→      // 인용구
   341→      if (/^> ?/.test(line)) {
   342→        flushParagraph();
   343→        const result = parseBlockquote(lines, i);
   344→        html += result.html + '\n';
   345→        i = result.nextIndex;
   346→        continue;
   347→      }
   348→
   349→      // 목록 (순서 없는/있는)
   350→      if (/^(\s*)([-*+]|\d+[.)]) /.test(line)) {
   351→        flushParagraph();
   352→        const baseIndent = line.match(/^(\s*)/)[1].length;
   353→        const result = parseList(lines, i, baseIndent);
   354→        html += result.html + '\n';
   355→        i = result.nextIndex;
   356→        continue;
   357→      }
   358→
   359→      // 일반 텍스트: 문단에 추가
   360→      paragraphLines.push(line);
   361→      i++;
   362→    }
   363→
   364→    // 남은 문단 처리
   365→    flushParagraph();
   366→
   367→    return html;
   368→  }
   369→
   370→  return { parse };
   371→})();
   372→

