     1→/**
     2→ * editor.js
     3→ * 마크다운 에디터 로직
     4→ *
     5→ * 기능:
     6→ * - 실시간 미리보기 업데이트
     7→ * - 툴바 버튼 액션 (선택 영역 래핑 포함)
     8→ * - 드래그로 패널 크기 조절
     9→ * - 키보드 단축키 (Ctrl+B, Ctrl+I, Ctrl+K)
    10→ * - localStorage 자동 저장/복원
    11→ * - HTML 내보내기
    12→ */
    13→
    14→(() => {
    15→  // ============================
    16→  // 상수
    17→  // ============================
    18→  const STORAGE_KEY = 'markdown-editor-content';
    19→  const AUTO_SAVE_DELAY_MS = 1000;
    20→  const SAVE_INDICATOR_DURATION_MS = 2000;
    21→
    22→  const DEFAULT_CONTENT = `# 마크다운 에디터에 오신 것을 환영합니다
    23→
    24→이 에디터는 **실시간 미리보기**를 지원하는 마크다운 편집기입니다.
    25→
    26→## 기능 소개
    27→
    28→### 텍스트 스타일
    29→
    30→- **굵게** 텍스트
    31→- *기울임* 텍스트
    32→- ***굵은 기울임*** 텍스트
    33→- \`인라인 코드\`
    34→- ~~취소선~~ 텍스트
    35→
    36→### 코드 블록
    37→
    38→\`\`\`javascript
    39→function greet(name) {
    40→  console.log(\`안녕하세요, \${name}!\`);
    41→}
    42→
    43→greet('세상');
    44→\`\`\`
    45→
    46→### 목록
    47→
    48→순서 없는 목록:
    49→- 항목 1
    50→- 항목 2
    51→  - 중첩 항목 2.1
    52→  - 중첩 항목 2.2
    53→- 항목 3
    54→
    55→순서 있는 목록:
    56→1. 첫 번째
    57→2. 두 번째
    58→3. 세 번째
    59→
    60→### 인용구
    61→
    62→> 마크다운은 텍스트를 HTML로 변환하는 간단한 마크업 언어입니다.
    63→>
    64→> — John Gruber
    65→
    66→### 링크와 이미지
    67→
    68→[GitHub](https://github.com) - 코드 저장소
    69→
    70→### 수평선
    71→
    72→---
    73→
    74→### 단축키
    75→
    76→| 단축키 | 기능 |
    77→| --- | --- |
    78→| Ctrl+B | 굵게 |
    79→| Ctrl+I | 기울임 |
    80→| Ctrl+K | 링크 |
    81→`;
    82→
    83→  // ============================
    84→  // DOM 요소
    85→  // ============================
    86→  const editor = document.getElementById('editor');
    87→  const preview = document.getElementById('preview');
    88→  const resizer = document.getElementById('resizer');
    89→  const editorPane = document.getElementById('editor-pane');
    90→  const previewPane = document.getElementById('preview-pane');
    91→  const exportBtn = document.getElementById('export-btn');
    92→  const autoSaveIndicator = document.getElementById('auto-save-indicator');
    93→  const editorContainer = document.querySelector('.editor-container');
    94→
    95→  // ============================
    96→  // 미리보기 업데이트
    97→  // ============================
    98→  function updatePreview() {
    99→    const markdown = editor.value;
   100→
   101→    if (!markdown.trim()) {
   102→      preview.innerHTML = `
   103→        <div class="preview-empty">
   104→          <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
   105→            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
   106→            <polyline points="14 2 14 8 20 8"/>
   107→            <line x1="16" y1="13" x2="8" y2="13"/>
   108→            <line x1="16" y1="17" x2="8" y2="17"/>
   109→            <polyline points="10 9 9 9 8 9"/>
   110→          </svg>
   111→          <p>왼쪽에 마크다운을 입력하면 미리보기가 표시됩니다.</p>
   112→        </div>
   113→      `;
   114→      return;
   115→    }
   116→
   117→    preview.innerHTML = MarkdownParser.parse(markdown);
   118→  }
   119→
   120→  // ============================
   121→  // 자동 저장
   122→  // ============================
   123→  let autoSaveTimer = null;
   124→  let saveIndicatorTimer = null;
   125→
   126→  function scheduleAutoSave() {
   127→    if (autoSaveTimer) {
   128→      clearTimeout(autoSaveTimer);
   129→    }
   130→    autoSaveTimer = setTimeout(() => {
   131→      saveToLocalStorage();
   132→    }, AUTO_SAVE_DELAY_MS);
   133→  }
   134→
   135→  function saveToLocalStorage() {
   136→    try {
   137→      localStorage.setItem(STORAGE_KEY, editor.value);
   138→      showSaveIndicator();
   139→    } catch (err) {
   140→      console.warn('자동 저장 실패:', err);
   141→    }
   142→  }
   143→
   144→  function showSaveIndicator() {
   145→    if (saveIndicatorTimer) {
   146→      clearTimeout(saveIndicatorTimer);
   147→    }
   148→    autoSaveIndicator.classList.add('visible');
   149→    saveIndicatorTimer = setTimeout(() => {
   150→      autoSaveIndicator.classList.remove('visible');
   151→    }, SAVE_INDICATOR_DURATION_MS);
   152→  }
   153→
   154→  function restoreFromLocalStorage() {
