   172→  /**
   173→   * 선택 영역을 래핑하거나 플레이스홀더를 삽입한다.
   174→   * @param {string} prefix - 시작 문자열
   175→   * @param {string} suffix - 끝 문자열
   176→   * @param {string} placeholder - 선택 없을 때 삽입할 기본 텍스트
   177→   */
   178→  function wrapSelection(prefix, suffix, placeholder = '') {
   179→    editor.focus();
   180→
   181→    const start = editor.selectionStart;
   182→    const end = editor.selectionEnd;
   183→    const selectedText = editor.value.substring(start, end);
   184→    const insertText = selectedText || placeholder;
   185→
   186→    const before = editor.value.substring(0, start);
   187→    const after = editor.value.substring(end);
   188→
   189→    editor.value = before + prefix + insertText + suffix + after;
   190→
   191→    // 커서 위치 조정
   192→    const newStart = start + prefix.length;
   193→    const newEnd = newStart + insertText.length;
   194→    editor.setSelectionRange(newStart, newEnd);
   195→
   196→    updatePreview();
   197→    scheduleAutoSave();
   198→  }
   199→
   200→  /**
   201→   * 현재 줄의 시작에 접두사를 삽입한다.
   202→   * @param {string} prefix - 삽입할 접두사
   203→   * @param {string} placeholder - 선택 없을 때 삽입할 기본 텍스트
   204→   */
   205→  function insertLinePrefix(prefix, placeholder = '텍스트') {
   206→    editor.focus();
   207→
   208→    const start = editor.selectionStart;
   209→    const end = editor.selectionEnd;
   210→    const value = editor.value;
   211→
   212→    // 현재 선택 영역의 줄 시작 위치 찾기
   213→    const lineStart = value.lastIndexOf('\n', start - 1) + 1;
   214→
   215→    const selectedText = value.substring(start, end) || placeholder;
   216→    const before = value.substring(0, lineStart);
   217→    const after = value.substring(end);
   218→    const lineContent = value.substring(lineStart, start);
   219→
   220→    editor.value = before + prefix + lineContent + selectedText + after;
   221→
   222→    const newStart = lineStart + prefix.length + lineContent.length;
   223→    const newEnd = newStart + selectedText.length;
   224→    editor.setSelectionRange(newStart, newEnd);
   225→
   226→    updatePreview();
   227→    scheduleAutoSave();
   228→  }
   229→
   230→  /**
   231→   * 현재 줄 앞에 블록 요소를 삽입한다.
   232→   * @param {string} blockPrefix - 줄 앞에 삽입할 텍스트
   233→   * @param {string} placeholder - 기본 내용
   234→   */
   235→  function insertBlock(blockPrefix, placeholder) {
   236→    editor.focus();
   237→
   238→    const start = editor.selectionStart;
   239→    const value = editor.value;
   240→
   241→    // 현재 줄의 시작과 끝 찾기
   242→    const lineStart = value.lastIndexOf('\n', start - 1) + 1;
   243→    const lineEnd = value.indexOf('\n', start);
   244→    const actualEnd = lineEnd === -1 ? value.length : lineEnd;
   245→
   246→    const currentLineContent = value.substring(lineStart, actualEnd).trim();
   247→    const insertContent = currentLineContent || placeholder;
   248→
   249→    // 줄 앞이나 뒤에 개행 추가
   250→    const needsBefore = lineStart > 0 && value[lineStart - 1] !== '\n';
   251→    const needsAfter = actualEnd < value.length;
   252→
   253→    const before = value.substring(0, lineStart);
   254→    const after = value.substring(actualEnd);
   255→
   256→    const newContent =
   257→      (needsBefore ? '\n' : '') +
   258→      blockPrefix + insertContent +
   259→      (needsAfter ? '\n' : '');
   260→
   261→    editor.value = before + newContent + after;
   262→
   263→    const prefixOffset = needsBefore ? 1 : 0;
   264→    const newStart = lineStart + prefixOffset + blockPrefix.length;
   265→    const newEnd = newStart + insertContent.length;
   266→    editor.setSelectionRange(newStart, newEnd);
   267→
   268→    updatePreview();
   269→    scheduleAutoSave();
   270→  }
