   550→  function bindTabKey() {
   551→    editor.addEventListener('keydown', (e) => {
   552→      if (e.key !== 'Tab') return;
   553→      e.preventDefault();
   554→
   555→      const start = editor.selectionStart;
   556→      const end = editor.selectionEnd;
   557→      const value = editor.value;
   558→
   559→      if (start === end) {
   560→        // 단일 커서: 공백 2개 삽입
   561→        editor.value = value.substring(0, start) + '  ' + value.substring(end);
   562→        editor.setSelectionRange(start + 2, start + 2);
   563→      } else {
   564→        // 선택 영역: 각 줄에 들여쓰기 추가/제거
   565→        const selectedText = value.substring(start, end);
   566→        const lines = selectedText.split('\n');
   567→
   568→        let newText;
   569→        if (e.shiftKey) {
   570→          // 내어쓰기
   571→          newText = lines.map(line => line.startsWith('  ') ? line.substring(2) : line).join('\n');
   572→        } else {
   573→          // 들여쓰기
   574→          newText = lines.map(line => '  ' + line).join('\n');
   575→        }
   576→
   577→        editor.value = value.substring(0, start) + newText + value.substring(end);
   578→        editor.setSelectionRange(start, start + newText.length);
   579→      }
   580→
   581→      updatePreview();
   582→      scheduleAutoSave();
   583→    });
   584→  }
