   587→  // 드래그 리사이저
   588→  // ============================
   589→  function bindResizer() {
   590→    let isDragging = false;
   591→    let startX = 0;
   592→    let startEditorWidth = 0;
   593→    let isVertical = false;
   594→
   595→    resizer.addEventListener('mousedown', (e) => {
   596→      e.preventDefault();
   597→      isDragging = true;
   598→
   599→      const containerRect = editorContainer.getBoundingClientRect();
   600→      isVertical = window.innerWidth <= 768;
   601→
   602→      if (isVertical) {
   603→        startX = e.clientY;
   604→        startEditorWidth = editorPane.getBoundingClientRect().height;
   605→      } else {
   606→        startX = e.clientX;
   607→        startEditorWidth = editorPane.getBoundingClientRect().width;
   608→      }
   609→
   610→      resizer.classList.add('dragging');
   611→      document.body.style.cursor = isVertical ? 'row-resize' : 'col-resize';
   612→      document.body.style.userSelect = 'none';
   613→    });
   614→
   615→    document.addEventListener('mousemove', (e) => {
   616→      if (!isDragging) return;
   617→
   618→      const containerRect = editorContainer.getBoundingClientRect();
   619→
   620→      if (isVertical) {
   621→        const delta = e.clientY - startX;
   622→        const containerHeight = containerRect.height;
   623→        const newEditorHeight = startEditorWidth + delta;
   624→
   625→        // 최소/최대 크기 제한 (20% ~ 80%)
   626→        const minHeight = containerHeight * 0.2;
   627→        const maxHeight = containerHeight * 0.8;
   628→        const clampedHeight = Math.min(Math.max(newEditorHeight, minHeight), maxHeight);
   629→        const percentage = (clampedHeight / containerHeight) * 100;
   630→
   631→        editorPane.style.flex = 'none';
   632→        editorPane.style.height = `${percentage}%`;
   633→        previewPane.style.flex = '1';
   634→        previewPane.style.height = '';
   635→      } else {
   636→        const delta = e.clientX - startX;
   637→        const containerWidth = containerRect.width;
   638→        const newEditorWidth = startEditorWidth + delta;
   639→
   640→        // 최소/최대 크기 제한 (20% ~ 80%)
   641→        const minWidth = containerWidth * 0.2;
   642→        const maxWidth = containerWidth * 0.8;
   643→        const clampedWidth = Math.min(Math.max(newEditorWidth, minWidth), maxWidth);
   644→        const percentage = (clampedWidth / containerWidth) * 100;
   645→
   646→        editorPane.style.flex = 'none';
   647→        editorPane.style.width = `${percentage}%`;
   648→        previewPane.style.flex = '1';
   649→        previewPane.style.width = '';
   650→      }
   651→    });
   652→
   653→    document.addEventListener('mouseup', () => {
   654→      if (!isDragging) return;
   655→      isDragging = false;
   656→      resizer.classList.remove('dragging');
   657→      document.body.style.cursor = '';
   658→      document.body.style.userSelect = '';
   659→    });
   660→
   661→    // 터치 지원
   662→    resizer.addEventListener('touchstart', (e) => {
   663→      e.preventDefault();
   664→      const touch = e.touches[0];
   665→      isDragging = true;
   666→      isVertical = window.innerWidth <= 768;
   667→
   668→      if (isVertical) {
   669→        startX = touch.clientY;
   670→        startEditorWidth = editorPane.getBoundingClientRect().height;
   671→      } else {
   672→        startX = touch.clientX;
   673→        startEditorWidth = editorPane.getBoundingClientRect().width;
   674→      }
   675→
   676→      resizer.classList.add('dragging');
   677→    }, { passive: false });
   678→
   679→    document.addEventListener('touchmove', (e) => {
   680→      if (!isDragging) return;
   681→      const touch = e.touches[0];
   682→      const containerRect = editorContainer.getBoundingClientRect();
   683→
   684→      if (isVertical) {
   685→        const delta = touch.clientY - startX;
   686→        const containerHeight = containerRect.height;
   687→        const newEditorHeight = startEditorWidth + delta;
   688→        const minHeight = containerHeight * 0.2;
   689→        const maxHeight = containerHeight * 0.8;
   690→        const clampedHeight = Math.min(Math.max(newEditorHeight, minHeight), maxHeight);
   691→        const percentage = (clampedHeight / containerHeight) * 100;
   692→
   693→        editorPane.style.flex = 'none';
   694→        editorPane.style.height = `${percentage}%`;
   695→        previewPane.style.flex = '1';
   696→      } else {
   697→        const delta = touch.clientX - startX;
   698→        const containerWidth = containerRect.width;
   699→        const newEditorWidth = startEditorWidth + delta;
   700→        const minWidth = containerWidth * 0.2;
   701→        const maxWidth = containerWidth * 0.8;
   702→        const clampedWidth = Math.min(Math.max(newEditorWidth, minWidth), maxWidth);
   703→        const percentage = (clampedWidth / containerWidth) * 100;
   704→
   705→        editorPane.style.flex = 'none';
   706→        editorPane.style.width = `${percentage}%`;
   707→        previewPane.style.flex = '1';
   708→      }
   709→    }, { passive: true });
   710→
   711→    document.addEventListener('touchend', () => {
   712→      if (!isDragging) return;
   713→      isDragging = false;
   714→      resizer.classList.remove('dragging');
